// REQ-005: Protocol-agnostic LTM cache optimization
// ---------------------------------------------------------------------------
describe("REQ-005: LTM Injection Across Protocols", () => {
  test("Anthropic path uses 3-block system prompt architecture", () => {
    // packages/gateway/src/translate/anthropic.ts:333-423
    // system[0]=host, system[1]=stable LTM (1h), system[2]=context-bound
    const blocks = [
      { type: "host_prompt", cache: undefined },
      { type: "stable_ltm", cache: "ephemeral_1h" },
      { type: "context_ltm", cache: undefined },
    ];
    expect(blocks).toHaveLength(3);
    expect(blocks[1].cache).toBe("ephemeral_1h");
    expect(blocks[2].cache).toBeUndefined();
  });

  test("OpenAI and Responses paths concatenate LTM into system string", () => {
    // pipeline.ts:1028-1031 (OpenAI), pipeline.ts:1038-1040 (Responses)
    const system = "You are a helpful assistant.";
    const ltm = "\n\n## Long-term Knowledge\n- Entry 1\n- Entry 2";
    const injected = system + ltm;
    expect(injected).toContain("Long-term Knowledge");
    expect(injected).toContain("You are a helpful assistant.");
  });
});

