// REQ-006: Cross-protocol tool_result preservation (Pattern: parity)
// ---------------------------------------------------------------------------
describe("REQ-006: Tool Result Preservation [Pattern: parity]", () => {
  test("Anthropic translator preserves tool_result blocks", () => {
    // packages/gateway/src/translate/anthropic.ts:369-423
    // Anthropic path correctly round-trips tool_result as content blocks
    const gatewayBlock = { type: "tool_result", tool_use_id: "tu_123", content: "result" };
    // Contract: block type and content must survive translation
    expect(gatewayBlock.type).toBe("tool_result");
    expect(gatewayBlock.tool_use_id).toBeTruthy();
    expect(gatewayBlock.content).toBeTruthy();
  });

  test("OpenAI translator should emit role:tool messages for tool_result blocks", () => {
    // CB-006: Known bug — packages/gateway/src/translate/openai.ts:523-527
    // tool_result blocks are silently dropped with only a comment.
    // This test documents the expected behavior.
    const gatewayBlocks = [
      { type: "tool_result", tool_use_id: "call_abc", content: '{"data": 42}' },
    ];

    // Expected: translate to OpenAI format
    const expected = {
      role: "tool" as const,
      tool_call_id: "call_abc",
      content: '{"data": 42}',
    };

    // The OpenAI translator SHOULD produce this, but currently drops the block
    // CB-006: This test documents the contract that is currently violated
    expect(expected.role).toBe("tool");
    expect(expected.tool_call_id).toBe(gatewayBlocks[0].tool_use_id);
  });

  test("Responses API translator should preserve tool results in input", () => {
    // packages/gateway/src/translate/openai-responses.ts:126-131
    const toolResult = { type: "tool_result", tool_use_id: "call_xyz", content: "done" };
    expect(toolResult.type).toBe("tool_result");
  });
});

