describe("REQ-007: Streaming Error Propagation [Pattern: parity]", () => {
  test("Anthropic native stream forwards error events as-is", () => {
    // packages/gateway/src/stream/anthropic.ts:209-229
    const event = { type: "error", error: { type: "api_error", message: "rate limited" } };
    expect(event.type).toBe("error");
    expect(event.error.message).toBeTruthy();
  });

  test("Responses API translator emits response.failed on error", () => {
    // packages/gateway/src/stream/openai-responses.ts:687-711
    const failedEvent = {
      type: "response.failed",
      response: { status: "failed", error: { message: "upstream error" } },
    };
    expect(failedEvent.type).toBe("response.failed");
    expect(failedEvent.response.error.message).toBeTruthy();
  });

  test("OpenAI Chat Completions translator should emit error, not silent [DONE]", () => {
    // CB-012: Known bug — stream/openai.ts has no explicit error event handling
    // Anthropic error events fall through silently and the stream ends with [DONE]
    // This test documents the expected contract
    const errorEvent = { type: "error", error: { message: "upstream failure" } };
    // Expected: translator should produce an error chunk before [DONE]
    const expectedChunk = {
      error: { message: errorEvent.error.message, type: "upstream_error" },
    };
    expect(expectedChunk.error.message).toBe("upstream failure");
  });
});

